declare module '*.css' {}
declare module '*.css?raw' {
	const content: string;
	export default content;
}
declare module '*.css?inline' {
	const content: string;
	export default content;
}
declare module '*.html?raw' {
	const content: string;
	export default content;
}
declare module '*.tsx?raw' {
	const content: string;
	export default content;
}
declare module '*.ts?raw' {
	const content: string;
	export default content;
}
